('VW3_2021_consolidated_inventory_2', 'VW3', 2021, 'consolidated', 'Chi phí sản xuất kinh doanh dở dang', 'construction_in_progress', 55769593588.0, NULL, 'Bao gồm Công trình CW2 Vĩnh Phúc (13,57 tỷ), Gói 4 Ý Yên Nam Định - Vụ Băn (6,74 tỷ), Công trình Ô19B Hoàng Mai (15,21 tỷ), Thi công nhà máy nước Hoà Liên (14,17 tỷ) và các công trình khác (6,07 tỷ)'),
('VW3_2021_consolidated_inventory_3', 'VW3', 2021, 'consolidated', 'Nợ quá hạn trên 3 năm', 'raw_material', 17770573998.0, 1138909028.0, 'Chủ yếu là các khoản phải thu các Ban quản lý Dự án thuộc Dự án đầu tư bằng vốn Ngân sách nhà nước (Hạ tầng Tả Ngạn, Phúc Thọ, Chương trình nước sạch Nông thôn...). Các dự án hoàn thành từ 2017-2018, đang chờ phê duyệt quyết toán chính thức. Số nợ quá hạn từ các BQLDA Ngân sách là 11,71 tỷ.'),
('VW3_2023_consolidated_inventory_0', 'VW3', 2023, 'consolidated', 'Nguyên liệu, vật liệu', 'raw_material', 7038772569.0, 0.0, 'Vật tư, hàng hóa như ống gang, ống thép, cút, bích, tê do thay đổi thiết kế của chủ đầu tư nên thừa, được bảo quản và lưu tại kho, bãi, đảm bảo chất lượng'),
